function extractListForSchoolType(school) {
    const listaLiceum = school.data.lista_kierunkow.filter((kierunek)=>kierunek.kierunek?.typ_kierunku === "liceum");
    const listaTechnikum = school.data.lista_kierunkow.filter((kierunek)=>kierunek.kierunek?.typ_kierunku === "technikum");
    const listaSzkolaZawodowa = school.data.lista_kierunkow.filter((kierunek)=>kierunek.kierunek?.typ_kierunku === "szkola_zawodowa");
    return {
        listaLiceum,
        listaTechnikum,
        listaSzkolaZawodowa
    };
}
